### 1. Add logging to validateResourceReference()
In `pkg/manifest/manifest.go` (lines 209-241):

```go
func validateResourceReference(ref string) error {
    // Need to get logger from somewhere - see note below
    if logger != nil {
        logger.Debug("validating resource reference",
            "reference", ref,
            "parser", "manifest.validateResourceReference")
    }

    if ref == "" {
        if logger != nil {
            logger.Error("validation failed",
                "reference", ref,
                "reason", "empty reference")
        }
        return fmt.Errorf("resource reference cannot be empty")
    }

    parts := strings.Split(ref, "/")
    if logger != nil {
        logger.Debug("split reference",
            "reference", ref,
            "parts", parts,
            "count", len(parts))
    }

    if len(parts) < 2 {
        if logger != nil {
            logger.Error("validation failed",
                "reference", ref,
                "reason", "invalid format - too few parts",
                "parts_count", len(parts),
                "expected", "at least 2")
        }
        return fmt.Errorf("invalid format (expected type/name): %q", ref)
    }

    resourceType := parts[0]
    name := strings.Join(parts[1:], "/")

    if logger != nil {
        logger.Debug("parsed reference",
            "reference", ref,
            "type", resourceType,
            "name", name)
    }

    // Validate resource type
    validTypes := []string{"command", "skill", "agent", "package"}
    isValidType := false
    for _, t := range validTypes {
        if resourceType == t {
            isValidType = true
            break
        }
    }
    if !isValidType {
        if logger != nil {
            logger.Error("validation failed",
                "reference", ref,
                "reason", "invalid resource type",
                "type", resourceType,
                "valid_types", validTypes)
        }
        return fmt.Errorf("invalid resource type %q (expected: command, skill, agent, or package)", resourceType)
    }

    // Validate name is not empty
    if name == "" {
        if logger != nil {
            logger.Error("validation failed",
                "reference", ref,
                "reason", "empty name")
        }
        return fmt.Errorf("resource name cannot be empty")
    }

    if logger != nil {
        logger.Debug("validation passed",
            "reference", ref,
            "type", resourceType,
            "name", name)
    }

    return nil
}
```

