func ParseResourceArg(arg string) (resource.ResourceType, string, error) {
    // Need logger - see note below
    if logger != nil {
        logger.Debug("parsing resource argument",
            "argument", arg,
            "parser", "cmd.ParseResourceArg",
            "method", "strings.SplitN(arg, \"/\", 2)")
    }

    parts := strings.SplitN(arg, "/", 2)
    if logger != nil {
        logger.Debug("split argument",
            "argument", arg,
            "parts", parts,
            "count", len(parts))
    }

    if len(parts) != 2 {
        if logger != nil {
            logger.Error("parsing failed",
                "argument", arg,
                "reason", "invalid format",
                "parts_count", len(parts),
                "expected", 2)
        }
        return "", "", fmt.Errorf("invalid format: must be 'type/name' (e.g., skill/my-skill, command/my-command, agent/my-agent)")
    }

    typeStr := strings.TrimSpace(parts[0])
    name := strings.TrimSpace(parts[1])

    if logger != nil {
        logger.Debug("parsed argument",
            "argument", arg,
            "type", typeStr,
            "name", name)
    }

    if name == "" {
        if logger != nil {
            logger.Error("parsing failed",
                "argument", arg,
                "reason", "empty name")
        }
        return "", "", fmt.Errorf("resource name cannot be empty")
    }

    // Parse and validate type
    resourceType, err := parseResourceType(typeStr)
    if err != nil {
        if logger != nil {
            logger.Error("parsing failed",
                "argument", arg,
                "reason", "invalid resource type",
                "type", typeStr,
                "error", err)
        }
        return "", "", err
    }

    if logger != nil {
        logger.Debug("parsing succeeded",
            "argument", arg,
            "type", resourceType,
            "name", name)
    }

    return resourceType, name, nil
}
```

### 3. Design Decision: How to Access Logger

**Problem:** These functions don't have access to the logger currently.

**Options:**

**A. Pass logger as parameter** (most explicit)
```go
func validateResourceReference(ref string, logger *slog.Logger) error
func ParseResourceArg(arg string, logger *slog.Logger) (resource.ResourceType, string, error)
```
- Pros: Explicit, testable, no globals
- Cons: Changes many function signatures

**B. Use context.Context** (idiomatic Go)
```go
func validateResourceReference(ctx context.Context, ref string) error
// Extract logger from context
logger := logging.LoggerFromContext(ctx)
```
- Pros: Idiomatic, extensible
- Cons: Requires context plumbing

**C. Package-level logger** (simplest but not ideal)
```go
var logger *slog.Logger

func SetLogger(l *slog.Logger) {
    logger = l
}
```
- Pros: Minimal changes
- Cons: Global state, harder to test

**Recommendation:** Start with **Option C** for quick implementation, consider refactoring to **Option B** later.

