## Suggested fix

Add two methods on BulkImportOptions:

\`\`\`go
func (opts BulkImportOptions) resolveSource(sourcePath string) (url, typ, ref string) {
    if opts.SourceURL != \"\" && opts.SourceType != \"\" {
        return opts.SourceURL, opts.SourceType, opts.Ref
    }
    absPath, err := filepath.Abs(sourcePath)
    if err != nil {
        absPath = sourcePath
    }
    return \"file://\" + absPath, \"file\", \"\"
}

func (opts BulkImportOptions) toImportOptions() ImportOptions {
    o := ImportOptions{
        SourceName: opts.SourceName,
